final:
module top_module(error, clk, req, ack, reset);output reg error;

input clk, req, ack, reset;

reg [2:0] invalid_state;

initial
begin
	invalid_state = 3'b000;
	error = 1'b0;
end

always @(posedge clk)
begin
	case (invalid_state)
		3'b000: 
		begin
			if (~req && ~ack)
				invalid_state = 3'b000;
			else if (req && ~ack)
				invalid_state = 3'b001;
			else
			begin
				invalid_state = 3'b100;
				error = 1'b1;
			end
		end

		3'b001:
		begin
			if (req && ~ack)
				invalid_state = 3'b001;
			else if (req && ack)
				invalid_state = 3'b010;
			else
			begin
				invalid_state = 3'b100;
				error = 1'b1;
			end
		end

		3'b010:
		begin
			if (req && ack)
				invalid_state = 3'b010;
			else if (~req && ack)
				invalid_state = 3'b011;
			else
			begin
				invalid_state = 3'b100;
				error = 1'b1;
			end
		end

		3'b011:
		begin
			if (~req && ack)
				invalid_state = 3'b011;
			else if (~req && ~ack)
				invalid_state = 3'b000;
			else
			begin
				invalid_state = 3'b100;
				error = 1'b1;
			end
		end

		3'b100:
		begin
			if (reset)
			begin
				invalid_state = 3'b000;
				error = 1'b0;
			end
		end

		default:
		begin
			invalid_state = 3'b100;
			error = 1'b1;
		end
	endcase
end

endmodule
